def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val size = c.toInt
  val parent = Array.fill(size + 1)(0)
  val rank = Array.fill(size + 1)(0)

  for (i <- 1 to size) {
    parent(i) = i
    rank(i) = 1
  }

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val xroot = find(x)
    val yroot = find(y)
    if (xroot == yroot) return
    if (rank(xroot) < rank(yroot)) {
      parent(xroot) = yroot
    } else {
      parent(yroot) = xroot
      if (rank(xroot) == rank(yroot)) rank(xroot) += 1
    }
  }

  for (conn <- connections) {
    val u = conn(0).toInt
    val v = conn(1).toInt
    union(u, v)
  }

  val components = Array.fill(size + 1)(scala.collection.mutable.ListBuffer[Int]())
  for (i <- 1 to size) {
    val root = find(i)
    components(root) += i
  }

  val componentTreeSets = scala.collection.mutable.HashMap[Int, scala.collection.mutable.TreeSet[Int]]()
  for (root <- 1 to size) {
    val stations = components(root)
    val treeSet = scala.collection.mutable.TreeSet(stations: _*)
    componentTreeSets(root) = treeSet
  }

  val online = Array.fill(size + 1)(true)
  val result = scala.collection.mutable.ListBuffer[Long]()

  for (query <- queries) {
    val t = query(0).toInt
    val x = query(1).toInt
    if (t == 1) {
      if (online(x)) {
        result += x.toLong
      } else {
        val root = find(x)
        val treeSet = componentTreeSets(root)
        if (treeSet.isEmpty) {
          result += -1.toLong
        } else {
          result += treeSet.min.toLong
        }
      }
    } else {
      if (online(x)) {
        online(x) = false
        val root = find(x)
        componentTreeSets(root).remove(x)
      }
    }
  }

  result.toArray
}
